/* ============================================================
   ===== МОДУЛЬ ДЕКЛАРАЦИЙ / DEKLARACIJE =====
   Справочник по продуктам (отдельный ключ declProducts), ручной
   генератор и генерация из заказа. PDF — общий конвейер
   html2canvas + jsPDF. Прикрепление — cloudOrderDocUpload.
   ============================================================ */
var DECL_ALLERGENS=[
  ['gluten','Глутен (житарице)','Глютен (злаки)'],
  ['jaja','Јаја','Яйца'],
  ['mleko','Млеко (лактоза)','Молоко (лактоза)'],
  ['soja','Соја','Соя'],
  ['orasi','Орашасти плодови','Орехи'],
  ['kikiriki','Кикирики','Арахис'],
  ['susam','Сусам','Кунжут'],
  ['slacica','Сенф','Горчица'],
  ['celer','Целер','Сельдерей'],
  ['riba','Риба','Рыба'],
  ['rak','Ракови','Ракообразные'],
  ['mekusci','Мекушци','Моллюски'],
  ['sulfiti','Сулфити (SO₂)','Сульфиты (SO₂)'],
  ['lupina','Лупина','Люпин']
];
var DECL_NUTR=[['energy','Енергија / Энергия'],['fat','Масти / Жиры'],['satfat','— засићене / насыщ.'],
  ['carb','Угљени хидрати / Углеводы'],['sugar','— шећери / сахара'],['protein','Протеини / Белки'],['salt','Со / Соль']];

var BV_LOGO_PNG='data:image/png;base64,';
var BV_DOC_LOGO_PNG="data:image/png;base64,";
function declLotFromDate(iso){var d=iso?new Date(iso+'T00:00:00'):new Date();if(isNaN(d))d=new Date();return String(d.getFullYear()).slice(2)+('0'+(d.getMonth()+1)).slice(-2)+('0'+d.getDate()).slice(-2);}
function declNextNum(){docConfig.counters=docConfig.counters||{};return 'DEKL-'+new Date().getFullYear()+'-'+String((docConfig.counters.deklaracija||0)+1).padStart(3,'0');}
function declFileName(ctx){var d=ctx.date?new Date(ctx.date+'T00:00:00'):new Date();if(isNaN(d))d=new Date();var ds=('0'+d.getDate()).slice(-2)+'-'+('0'+(d.getMonth()+1)).slice(-2)+'-'+d.getFullYear();return ('Deklaracija_'+(ctx.number||'')+'_'+ds).replace(/[^\w\-]/g,'_')+'.pdf';}
function declBumpCounter(){docConfig.counters=docConfig.counters||{};docConfig.counters.deklaracija=(docConfig.counters.deklaracija||0)+1;cloudPut('docConfig',docConfig);}
/* авто-добавление получателя в партнёры, если его ещё нет */
function declEnsurePartner(name){
  name=(name||'').trim();if(!name)return;
  var norm=name.toLowerCase();
  var exists=(partners||[]).some(function(p){return (p.name||'').trim().toLowerCase()===norm;});
  if(exists)return;
  var code=genCode();var tries=0;
  while((partners||[]).some(function(p){return p.code===code;})&&tries<20){code=genCode();tries++;}
  partners.push({id:uid(),name:name,phone:'',code:code,active:true,created:Date.now(),autoFromDecl:true});
  savePartners();
  if(typeof renderPartners==='function')try{renderPartners();}catch(e){}
  toast('Новый партнёр добавлен: '+name+' · код '+code);
}
/* запись в архив деклараций */
function declArchiveAdd(ctx,pdf,source,orderId){
  declArchive.unshift({
    ts:new Date().toISOString(),
    number:ctx.number||'',date:ctx.date||'',
    recipient:ctx.recipient||'',addr:ctx.addr||'',lot:ctx.lot||'',
    products:(ctx.products||[]).map(function(p){return {name:p.name,weight:p.weight||'',prodDate:p.prodDate||''};}),
    url:(pdf&&pdf.url)||'',view:(pdf&&pdf.view)||'',
    source:source||'manual',orderId:orderId||''
  });
  if(declArchive.length>500)declArchive=declArchive.slice(0,500);
  cloudPut('declArchive',declArchive);
}
/* загрузка PDF в Drive (для ручных деклараций) */
function declDriveUpload(fname,b64,cb){
  if(!GAS_URL){cb(null);return;}
  fetch(GAS_URL,{method:'POST',headers:{'Content-Type':'text/plain;charset=utf-8'},
    body:JSON.stringify({master:MASTER,driveUpload:true,fileName:fname,mime:'application/pdf',dataB64:b64})})
  .then(function(r){return r.json();}).then(function(j){cb(j&&j.ok?{url:j.download,view:j.view}:null);}).catch(function(){cb(null);});
}
/* скачать локально из base64 */
function declDownloadB64(b64,fname){
  try{
    var bin=atob(b64),arr=new Uint8Array(bin.length);
    for(var i=0;i<bin.length;i++)arr[i]=bin.charCodeAt(i);
    var blob=new Blob([arr],{type:'application/pdf'}),url=URL.createObjectURL(blob);
    var a=document.createElement('a');a.href=url;a.download=fname;document.body.appendChild(a);a.click();
    setTimeout(function(){URL.revokeObjectURL(url);try{a.remove();}catch(e){}},1500);
  }catch(e){toast('Не удалось скачать файл');}
}
/* рендер архива деклараций */
function renderDeclArchive(){
  var w=document.getElementById('declArchList');if(!w)return;
  if(!declArchive.length){w.innerHTML='<div class="hint">Архив пуст. Выставленные декларации появятся здесь.</div>';return;}
  w.innerHTML=declArchive.map(function(a){
    var dt='';try{dt=new Date(a.ts).toLocaleString('ru-RU',{day:'2-digit',month:'2-digit',year:'2-digit',hour:'2-digit',minute:'2-digit'});}catch(e){dt=a.date||'';}
    var prods=(a.products||[]).map(function(p){return esc(p.name)+(p.weight?' ('+esc(p.weight)+')':'');}).join(', ');
    var src=a.source==='order'?('из заказа'+(a.orderId?' '+esc(a.orderId):'')):'вручную';
    var link=a.url?('<a href="'+esc(a.url)+'" target="_blank" rel="noopener" class="btn btn-line btn-sm" style="text-decoration:none;white-space:nowrap;">⬇ PDF</a>'):'<span class="hint">нет файла</span>';
    return '<div style="display:flex;gap:12px;align-items:flex-start;padding:10px 0;border-top:1px solid var(--line);">'+
      '<div style="flex:1;min-width:0;">'+
        '<div><b>'+esc(a.number||'—')+'</b> · '+esc(a.recipient||'—')+' <span class="hint">· '+src+'</span></div>'+
        '<div class="hint" style="margin-top:2px;">'+dt+(a.lot?' · LOT '+esc(a.lot):'')+'</div>'+
        '<div class="hint" style="margin-top:2px;">'+prods+'</div>'+
      '</div>'+link+'</div>';
  }).join('');
}
function declKey(name,weight){return String(name||'')+'|'+String(weight||'');}
function declGet(name,weight){
  return declProducts[declKey(name,weight)]||null;
}
/* Объединяет данные товара каталога + справочник деклараций в готовую запись */
function declResolve(name,weight){
  var cat=null;catalog.forEach(function(it){if(it.name===name&&(it.weight||'')===(weight||''))cat=it;});
  if(!cat)catalog.forEach(function(it){if(it.name===name)cat=it;});
  var d=declGet(name,weight)||(cat?declGet(cat.name,cat.weight):null)||{};
  return {
    name:name,weight:(weight||(cat&&cat.weight)||''),
    sastavRu:(d.sastavRu||(cat&&cat.sostav)||''),
    sastavSr:(d.sastavSr||(cat&&cat.sostavSr)||''),
    alg:Array.isArray(d.alg)?d.alg:[],
    qty:d.qty||(cat&&cat.weight)||'',
    shelfRu:d.shelfRu||'',shelfSr:d.shelfSr||'',
    storeRu:d.storeRu||'',storeSr:d.storeSr||'',
    nutr:d.nutr||{}
  };
}

/* ---------- СПРАВОЧНИК (редактор) ---------- */
function renderDeclRef(){
  var w=document.getElementById('declRef');if(!w)return;
  if(!catalog.length){w.innerHTML='<div class="hint">Сначала добавьте товары в прайс-лист.</div>';return;}
  var h='';
  catalog.forEach(function(it){
    var k=declKey(it.name,it.weight),d=declProducts[k]||{};
    var alg=Array.isArray(d.alg)?d.alg:[];
    var algBoxes=DECL_ALLERGENS.map(function(a){
      return '<label class="chk'+(alg.indexOf(a[0])>=0?' on':'')+'" style="font-size:12.5px;padding:6px 10px;">'+
        '<input type="checkbox" data-k="'+esc(k)+'" data-alg="'+a[0]+'"'+(alg.indexOf(a[0])>=0?' checked':'')+'>'+
        '<span>'+esc(a[1])+' / '+esc(a[2])+'</span></label>';
    }).join('');
    var nutr=d.nutr||{};
    var nutrInps=DECL_NUTR.map(function(n){
      return '<div class="field" style="margin:0;"><label class="lbl" style="font-size:10.5px;">'+esc(n[1])+'</label>'+
        '<input class="inp decl-n" data-k="'+esc(k)+'" data-n="'+n[0]+'" value="'+esc(nutr[n[0]]||'')+'" style="font-size:13px;padding:8px 10px;"></div>';
    }).join('');
    h+='<details class="card" style="margin-top:10px;padding:14px 16px;">'+
      '<summary style="cursor:pointer;font-weight:700;font-size:15px;list-style:none;">'+esc(it.name)+(it.weight?' · '+esc(it.weight):'')+
        (declRefFilled(k)?' <span style="color:var(--blue);font-size:12px;">● заполнено</span>':' <span class="hint" style="font-size:12px;">— не заполнено</span>')+'</summary>'+
      '<div style="margin-top:12px;">'+
        '<div style="display:flex;gap:10px;flex-wrap:wrap;">'+
          '<div class="field" style="flex:1;min-width:220px;margin:0;"><label class="lbl">Состав (RU)</label><textarea class="inp decl-f" data-k="'+esc(k)+'" data-f="sastavRu" rows="2" style="resize:vertical;">'+esc(d.sastavRu||it.sostav||'')+'</textarea></div>'+
          '<div class="field" style="flex:1;min-width:220px;margin:0;"><label class="lbl">Sastav (SR)</label><textarea class="inp decl-f" data-k="'+esc(k)+'" data-f="sastavSr" rows="2" style="resize:vertical;">'+esc(d.sastavSr||it.sostavSr||'')+'</textarea></div>'+
        '</div>'+
        '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-top:10px;">'+
          '<div class="field" style="min-width:120px;margin:0;"><label class="lbl">Нетто</label><input class="inp decl-f" data-k="'+esc(k)+'" data-f="qty" value="'+esc(d.qty||it.weight||'')+'"></div>'+
          '<div class="field" style="flex:1;min-width:120px;margin:0;"><label class="lbl">Рок (RU)</label><input class="inp decl-f" data-k="'+esc(k)+'" data-f="shelfRu" value="'+esc(d.shelfRu||'')+'" placeholder="3 дня"></div>'+
          '<div class="field" style="flex:1;min-width:120px;margin:0;"><label class="lbl">Rok (SR)</label><input class="inp decl-f" data-k="'+esc(k)+'" data-f="shelfSr" value="'+esc(d.shelfSr||'')+'" placeholder="3 dana"></div>'+
        '</div>'+
        '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-top:10px;">'+
          '<div class="field" style="flex:1;min-width:160px;margin:0;"><label class="lbl">Хранение (RU)</label><input class="inp decl-f" data-k="'+esc(k)+'" data-f="storeRu" value="'+esc(d.storeRu||'')+'" placeholder="В сухом месте, до 22 °C"></div>'+
          '<div class="field" style="flex:1;min-width:160px;margin:0;"><label class="lbl">Čuvanje (SR)</label><input class="inp decl-f" data-k="'+esc(k)+'" data-f="storeSr" value="'+esc(d.storeSr||'')+'" placeholder="Na suvom mestu, do 22 °C"></div>'+
        '</div>'+
        '<div class="lbl" style="margin:14px 0 6px;">Аллергены / Alergeni</div>'+
        '<div style="display:flex;flex-wrap:wrap;gap:6px;">'+algBoxes+'</div>'+
        '<div class="lbl" style="margin:14px 0 6px;">Пищевая ценность на 100 g / Nutritivne vrednosti</div>'+
        '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:8px;">'+nutrInps+'</div>'+
      '</div></details>';
  });
  w.innerHTML=h;
  /* привязка ввода */
  w.querySelectorAll('.decl-f').forEach(function(el){el.addEventListener('input',function(){
    var k=this.dataset.k,f=this.dataset.f;ensureDeclRec(k)[f]=this.value;});});
  w.querySelectorAll('.decl-n').forEach(function(el){el.addEventListener('input',function(){
    var rec=ensureDeclRec(this.dataset.k);rec.nutr=rec.nutr||{};rec.nutr[this.dataset.n]=this.value;});});
  w.querySelectorAll('input[data-alg]').forEach(function(cb){cb.addEventListener('change',function(){
    var rec=ensureDeclRec(this.dataset.k);rec.alg=Array.isArray(rec.alg)?rec.alg:[];
    var a=this.dataset.alg;
    if(this.checked){if(rec.alg.indexOf(a)<0)rec.alg.push(a);}else rec.alg=rec.alg.filter(function(x){return x!==a;});
    this.closest('.chk').classList.toggle('on',this.checked);});});
}
function declRefFilled(k){var d=declProducts[k];return d&&(d.sastavRu||d.sastavSr||(d.alg&&d.alg.length));}
function ensureDeclRec(k){if(!declProducts[k])declProducts[k]={alg:[],nutr:{}};return declProducts[k];}

