/* ---------- ПОСТРОЕНИЕ ДОКУМЕНТА ---------- */
function declAlgNames(alg){
  if(!alg||!alg.length)return '—';
  return alg.map(function(a){var x=null;DECL_ALLERGENS.forEach(function(z){if(z[0]===a)x=z;});return x?(x[1]+' / '+x[2]):a;}).join('; ');
}
function declBi(sr,ru){var s=esc(sr||'')||'—';if(ru)s+='<span class="ru">'+esc(ru)+'</span>';return s;}
function declProdBlock(p){
  var hasNutr=p.nutr&&Object.keys(p.nutr).some(function(k){return p.nutr[k]&&String(p.nutr[k]).trim();});
  var nutrRows=hasNutr?('<table class="ntable"><tr><td class="caphdr">Нутритивне вредности / Пищевая ценность</td><td class="caphdr">на 100 g</td></tr>'+
    DECL_NUTR.map(function(n){var v=p.nutr[n[0]];return (v&&String(v).trim())?('<tr><td>'+n[1]+'</td><td>'+esc(v)+'</td></tr>'):'';}).join('')+'</table>'):'';
  var sastav='';if(p.sastavSr)sastav+=esc(p.sastavSr);if(p.sastavRu)sastav+='<span class="ru">'+esc(p.sastavRu)+'</span>';if(!sastav)sastav='—';
  function row(ls,lr,v){return '<div class="drow"><div class="lbl3"><b>'+ls+'</b>'+lr+'</div><div class="val">'+v+'</div></div>';}
  return '<div class="pblock"><h3>'+esc(p.name)+(p.weight?' · '+esc(p.weight):'')+'</h3>'+
    row('Састав','Состав',sastav)+
    row('Алергени','Аллергены','<span class="alg"><b>'+declAlgNames(p.alg)+'</b></span>')+
    row('Нето количина','Нетто',esc(p.qty)||'—')+
    (p.prodDate?row('Датум производње','Дата производства',esc(declDateFmt(p.prodDate))):'')+
    row('Рок трајања','Срок годности',declBi(p.shelfSr,p.shelfRu))+
    row('Услови чувања','Условия хранения',declBi(p.storeSr,p.storeRu))+
    nutrRows+'</div>';
}
