  var blocks=ctx.products.map(declProdBlock).join('')||'<div style="text-align:center;color:#888;padding:18px;">Нет продуктов</div>';
  return declPdfCss()+'<div class="ddoc">'+declHeaderHtml(ctx)+blocks+declFooterHtml(ctx)+'</div>';
