function declDateFmt(iso){if(!iso)return new Date().toLocaleDateString('ru-RU');var p=String(iso).slice(0,10).split('-');return p.length===3?(p[2]+'.'+p[1]+'.'+p[0]):iso;}

/* ---------- РЕНДЕР PDF (общий конвейер) ---------- */
function declRenderPiece(html,cb){
  var holder=document.createElement('div');
  holder.style.cssText='position:fixed;left:-9999px;top:0;width:760px;background:#fff;';
  holder.innerHTML=declPdfCss()+'<div class="ddoc" style="padding:0;width:760px;">'+html+'</div>';
  document.body.appendChild(holder);
  var node=holder.lastChild;
  (document.fonts&&document.fonts.ready?document.fonts.ready:Promise.resolve()).then(function(){
    return window.html2canvas(node,{scale:2,backgroundColor:'#ffffff',useCORS:true,windowWidth:760});
  }).then(function(canvas){try{document.body.removeChild(holder);}catch(e){}cb(canvas);})
   .catch(function(){try{document.body.removeChild(holder);}catch(e){}cb(null);});
}
function declRenderPdf(ctx,returnB64,cb){
  if(!window.html2canvas||!(window.jspdf&&window.jspdf.jsPDF)){toast('Не загрузились библиотеки PDF — обновите страницу');return;}
  var jsPDF=window.jspdf.jsPDF,pdf=new jsPDF('p','mm','a4');
  var pageW=210,pageH=297,margin=12,usableW=pageW-2*margin,gap=4;
  var y=margin,first=true;
  var pieces=[declHeaderHtml(ctx)].concat((ctx.products||[]).map(declProdBlock)).concat([declFooterHtml(ctx)]);
  var i=0;
  function finish(){
    if(returnB64){var ds=pdf.output('datauristring');var ix=ds.indexOf('base64,');cb(ix>=0?ds.slice(ix+7):'');}
    else{pdf.save(declFileName(ctx));if(cb)cb();}
  }
  function step(){
    if(i>=pieces.length){finish();return;}
    declRenderPiece(pieces[i],function(canvas){
      if(canvas&&canvas.height){
        var imgW=usableW,imgH=canvas.height*imgW/canvas.width;
        // блок не влезает в остаток страницы — переносим целиком
        if(!first&&(y+imgH>pageH-margin)){pdf.addPage();y=margin;}
        // если блок выше целой страницы (очень длинный) — режем его постранично
        if(imgH>pageH-2*margin){
          var pxPerMm=canvas.width/imgW,pageContentPx=(pageH-2*margin)*pxPerMm,sy=0;
          while(sy<canvas.height){
            if(y>margin){pdf.addPage();y=margin;}
            var sliceH=Math.min(pageContentPx,canvas.height-sy);
            var cv=document.createElement('canvas');cv.width=canvas.width;cv.height=sliceH;
            cv.getContext('2d').drawImage(canvas,0,sy,canvas.width,sliceH,0,0,canvas.width,sliceH);
            pdf.addImage(cv.toDataURL('image/jpeg',0.95),'JPEG',margin,y,imgW,sliceH/pxPerMm);
            y+=sliceH/pxPerMm+gap;sy+=sliceH;
          }
        } else {
          pdf.addImage(canvas.toDataURL('image/jpeg',0.95),'JPEG',margin,y,imgW,imgH);
          y+=imgH+gap;
        }
        first=false;
      }
      i++;step();
    });
  }
  step();
}
function declPrint(ctx){
  var w=window.open('','_blank');if(!w){toast('Разрешите всплывающие окна для печати');return;}
  var pcss='<style>@page{size:auto;margin:0}html,body{margin:0;padding:0;background:#fff}.ddoc{width:auto !important;padding:13mm 12mm !important;}</style>';
  w.document.write('<!doctype html><html><head><meta charset="utf-8"><title> </title>'+pcss+'</head><body>'+declBuildHTML(ctx)+'<scr'+'ipt>window.onload=function(){setTimeout(function(){window.print();},300);}</scr'+'ipt></body></html>');
  w.document.close();
}

/* ---------- РУЧНОЙ ГЕНЕРАТОР: собрать ctx ---------- */
/* ===== ЭТИКЕТКИ ДЛЯ НАКЛЕЕК ===== */
var LBL_SIZES={
  a7:{w:105,h:74,max:8,fs:7,pad:3.5,sheetW:210},
  a6:{w:105,h:148,max:4,fs:9.5,pad:5,sheetW:210},
  a5:{w:210,h:148,max:2,fs:11.5,pad:8,sheetW:210},
  a4:{w:210,h:287,max:1,fs:13.5,pad:14,sheetW:210}
};
var lblSize='a7';
function declLabelInner(p,opts){
  var s=sellerData();
  var algNames=declAlgNames(p.alg);
  var nutrParts=[];
  if(p.nutr){
    if(p.nutr.energy)nutrParts.push('Е '+esc(p.nutr.energy));
    if(p.nutr.protein)nutrParts.push('Б '+esc(p.nutr.protein));
    if(p.nutr.fat)nutrParts.push('Ж '+esc(p.nutr.fat));
    if(p.nutr.carb)nutrParts.push('У '+esc(p.nutr.carb));
    if(p.nutr.salt)nutrParts.push('соль '+esc(p.nutr.salt));
  }
  var nutr=nutrParts.length?('<div class="ln">Nutr./Пищ.ц. (100g): '+nutrParts.join(' · ')+'</div>'):'';
  var sastav='';
  if(p.sastavSr)sastav+='<b>Sastav:</b> '+esc(p.sastavSr)+' ';
  if(p.sastavRu)sastav+='<span class="ru"><b>Состав:</b> '+esc(p.sastavRu)+'</span>';
  var shelf=[];if(p.shelfSr)shelf.push(esc(p.shelfSr));if(p.shelfRu&&p.shelfRu!==p.shelfSr)shelf.push(esc(p.shelfRu));
  var store=[];if(p.storeSr)store.push(esc(p.storeSr));if(p.storeRu&&p.storeRu!==p.storeSr)store.push(esc(p.storeRu));
  var meta='';
  if(opts&&opts.showMeta){
    var bits=[];if(opts.date)bits.push('Дат./Datum: '+esc(declDateFmt(opts.date)));if(opts.lot)bits.push('LOT '+esc(opts.lot));
    if(bits.length)meta='<div class="lm">'+bits.join(' · ')+'</div>';
  }
  return '<div class="lh"><img class="llogo" src="'+BV_LOGO_PNG+'" alt=""><div class="lt"><b>'+esc(p.name)+'</b>'+(p.weight?'<span class="lnet">'+esc(p.weight)+'</span>':'')+'</div></div>'+
    '<div class="lbody">'+
    (sastav?'<div class="ls">'+sastav+'</div>':'')+
    '<div class="la"><b>Alergeni / Аллергены:</b> '+algNames+'</div>'+
    nutr+
    (shelf.length?'<div class="lr"><b>Rok/Срок:</b> '+shelf.join(' · ')+'</div>':'')+
    (store.length?'<div class="lr"><b>Čuvanje/Хранение:</b> '+store.join(' · ')+'</div>':'')+
    meta+
    '</div>'+
    '<div class="lf">'+esc(s.name)+' · PIB '+esc(s.pib)+'</div>';
}
function declLabelCss(sz){
  var c=LBL_SIZES[sz];
  return '<style>'+
  '*{box-sizing:border-box;margin:0;padding:0;}'+
  '@page{size:A4;margin:0;}'+
  'html,body{background:#fff;font-family:"Wix Madefor Text","Helvetica Neue",Arial,sans-serif;color:#1D1D1B;}'+
  '.sheet{display:flex;flex-wrap:wrap;align-content:flex-start;width:'+c.sheetW+'mm;}'+
  '.lbl-card{width:'+c.w+'mm;height:'+c.h+'mm;padding:'+c.pad+'mm;border:1px dashed #bbb;overflow:hidden;font-size:'+c.fs+'pt;line-height:1.4;display:flex;flex-direction:column;page-break-inside:avoid;}'+
  '.lh{display:flex;align-items:center;gap:'+(c.pad*0.7)+'mm;border-bottom:1.5px solid #1D1D1B;padding-bottom:'+(c.pad*0.5)+'mm;flex-shrink:0;}'+
  '.lbody{flex:1;display:flex;flex-direction:column;justify-content:space-around;padding:'+(c.pad*0.5)+'mm 0;}'+
  '.llogo{width:'+(c.fs*2.6)+'pt;height:'+(c.fs*2.6)+'pt;object-fit:contain;flex-shrink:0;}'+
  '.lt{flex:1;} .lt b{font-size:'+(c.fs*1.55)+'pt;font-weight:800;display:block;line-height:1.1;} .lnet{font-weight:700;font-size:'+(c.fs*1.1)+'pt;color:#47A2DA;}'+
  '.ls .ru{display:block;color:#555;}'+
  '.la b{color:#c0392b;}'+
  '.ln{color:#333;}'+
  '.lm{font-weight:700;}'+
  '.lf{flex-shrink:0;font-size:'+(c.fs*0.82)+'pt;color:#666;border-top:1px solid #ddd;padding-top:'+(c.pad*0.35)+'mm;}'+
  '</style>';
}
function declPrintLabels(){
  var items=[];
  document.querySelectorAll('.lbl-qty').forEach(function(i){
    var q=Math.max(0,parseInt(i.value,10)||0);if(!q)return;
    var p=declResolve(i.dataset.name,i.dataset.weight);
    if(!(p.sastavSr||p.sastavRu))return;
    for(var n=0;n<q;n++)items.push(p);
  });
  if(!items.length){toast('Укажите количество хотя бы у одного продукта (с заполненными данными)');return;}
  var showMeta=document.getElementById('lblShowMeta').checked;
  var opts={showMeta:showMeta,date:document.getElementById('lblDate').value,lot:document.getElementById('lblLot').value.trim()};
  var cells=items.map(function(p){return '<div class="lbl-card">'+declLabelInner(p,opts)+'</div>';}).join('');
  var w=window.open('','_blank');if(!w){toast('Разрешите всплывающие окна для печати');return;}
  w.document.write('<!doctype html><html><head><meta charset="utf-8"><title> </title>'+declLabelCss(lblSize)+'</head><body><div class="sheet">'+cells+'</div>'+
    '<scr'+'ipt>window.onload=function(){setTimeout(function(){window.print();},300);}</scr'+'ipt></body></html>');
  w.document.close();
}
function updateLblTotal(){
  var t=0;document.querySelectorAll('.lbl-qty').forEach(function(i){t+=Math.max(0,parseInt(i.value,10)||0);});
  var c=LBL_SIZES[lblSize];var sheets=t?Math.ceil(t/c.max):0;
  var el=document.getElementById('lblTotal');if(el)el.textContent=t?('Всего этикеток: '+t+' · листов A4: '+sheets):'Укажите количество';
}
function renderLabelBuilder(){
  var w=document.getElementById('lblBuilder');if(!w)return;
  if(!catalog.length){w.innerHTML='<div class="hint">Нет товаров в прайс-листе.</div>';return;}
  w.innerHTML=catalog.map(function(it){var k=declKey(it.name,it.weight);var filled=declRefFilled(k);
    return '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">'+
      '<span style="flex:1;min-width:200px;">'+esc(it.name)+(it.weight?' · '+esc(it.weight):'')+(filled?'':' <span class="hint" style="color:#c0392b;">(нет данных)</span>')+'</span>'+
      '<input type="number" class="inp lbl-qty" min="0" max="200" value="0" data-name="'+esc(it.name)+'" data-weight="'+esc(it.weight||'')+'" style="width:80px;font-size:13px;padding:6px 9px;text-align:center;">'+
      '</div>';
  }).join('');
  w.querySelectorAll('.lbl-qty').forEach(function(i){i.addEventListener('input',updateLblTotal);});
  updateLblTotal();
}
function initLabelUi(){
  renderLabelBuilder();
  var di=document.getElementById('lblDate');if(di&&!di.value)di.valueAsDate=new Date();
  var seg=document.getElementById('lblSizeSeg');
  if(seg&&!seg._b){seg._b=1;seg.querySelectorAll('.seg-b').forEach(function(b){b.addEventListener('click',function(){
    seg.querySelectorAll('.seg-b').forEach(function(x){x.classList.remove('active');});this.classList.add('active');
    lblSize=this.dataset.size;updateLblTotal();});});}
  var mr=document.getElementById('lblShowMeta');
  if(mr&&!mr._b){mr._b=1;var row=document.getElementById('lblMetaRow');var upd=function(){row.style.display=mr.checked?'flex':'none';};mr.addEventListener('change',upd);upd();}
  var pb=document.getElementById('lblPrint');
  if(pb&&!pb._b){pb._b=1;pb.addEventListener('click',declPrintLabels);}
}
function declManualCtx(){
  var picks=[];
  document.querySelectorAll('.declpick-row').forEach(function(row){
    var cb=row.querySelector('.decl-pick');
    if(cb&&cb.checked){
      var p=declResolve(cb.dataset.name,cb.dataset.weight);
      var di=row.querySelector('.decl-pdate');
      p.prodDate=di?di.value:'';
      picks.push(p);
    }
  });
  return {
    recipient:document.getElementById('declRecipient').value.trim(),
    addr:document.getElementById('declAddr').value.trim(),
    date:document.getElementById('declDate').value,
    lot:document.getElementById('declLot').value.trim()||declLotFromDate(document.getElementById('declDate').value),
    number:document.getElementById('declNum').value.trim()||declNextNum(),
    products:picks
  };
}

/* ---------- ГЕНЕРАЦИЯ ИЗ ЗАКАЗА ---------- */
var declOrderState=null;
function openOrderDecl(orderId){
  var o=null;adminOrders.forEach(function(x){if(x.order_id===orderId)o=x;});if(!o){toast('Заказ не найден');return;}
  var prof=(profilesAdmin&&profilesAdmin[o.partner_id])||{};
  var savedParty=(docConfig.parties&&docConfig.parties[o.partner_id])||{};
  var prods=(o.items||[]).map(function(it){return declResolve(it.name,it.weight);});
  docConfig.counters=docConfig.counters||{};
  var num='DEKL-'+new Date().getFullYear()+'-'+String((docConfig.counters.deklaracija||0)+1).padStart(3,'0');
  var today=new Date().toISOString().slice(0,10);
  declOrderState={
    orderId:orderId,
    recipient:savedParty.name||prof.company||o.partner||'',
    addr:savedParty.address||(o.delivery&&o.delivery.address)||'',
    date:today,lot:'',number:num,products:prods
  };
  renderDeclOrderModal();
  document.getElementById('declOrderModal').style.display='flex';
}
function renderDeclOrderModal(){
  var d=declOrderState;
  document.getElementById('declOrderTitle').textContent='Декларация — '+d.orderId;
  var missing=d.products.filter(function(p){return !(p.sastavRu||p.sastavSr);}).length;
  var warn=missing?('<div class="hint" style="color:#c0392b;margin-bottom:12px;">⚠️ У '+missing+' позиц. не заполнен состав в справочнике. Можно сформировать, но лучше дозаполнить во вкладке «Декларации».</div>'):'';
  var rows=d.products.map(function(p,i){
    return '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;padding:8px 0;border-top:1px solid var(--line);">'+
      '<div style="flex:1;min-width:200px;"><b>'+esc(p.name)+'</b>'+(p.weight?' · '+esc(p.weight):'')+
        (!(p.sastavRu||p.sastavSr)?' <span class="hint" style="color:#c0392b;">(нет состава)</span>':'')+'</div>'+
      '<div style="display:flex;align-items:center;gap:6px;"><span class="hint" style="white-space:nowrap;">Дата произв.:</span>'+
      '<input type="date" class="inp declord-pdate" data-i="'+i+'" value="'+(p.prodDate||d.date)+'" style="width:auto;font-size:13px;padding:6px 9px;"></div>'+
      '</div>';
  }).join('');
  document.getElementById('declOrderBody').innerHTML=
    warn+
    '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:6px;">'+
      '<div class="field" style="flex:1;min-width:160px;margin:0;"><label class="lbl">Получатель</label><input class="inp" id="declOrdRecipient" value="'+esc(d.recipient)+'"></div>'+
      '<div class="field" style="min-width:140px;margin:0;"><label class="lbl">Дата отгрузки</label><input class="inp" id="declOrdDate" type="date" value="'+esc(d.date)+'"></div>'+
    '</div>'+
    '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:10px;">'+
      '<div class="field" style="min-width:140px;margin:0;"><label class="lbl">Партия (LOT)</label><input class="inp" id="declOrdLot" placeholder="общий, необяз."></div>'+
      '<div class="field" style="min-width:140px;margin:0;"><label class="lbl">№ документа</label><input class="inp" id="declOrdNum" value="'+esc(d.number)+'"></div>'+
    '</div>'+
    '<div class="lbl" style="margin:12px 0 4px;">Даты производства по продуктам</div>'+
    rows;
  document.getElementById('declOrderFoot').innerHTML=
    '<button class="btn btn-primary btn-sm" id="declOrdGo">Сформировать и прикрепить</button>'+
    '<button class="btn btn-line btn-sm" id="declOrdCancel">Отмена</button>'+
    '<span class="hint" id="declOrdStatus" style="margin-left:auto;"></span>';
  document.getElementById('declOrdGo').addEventListener('click',doOrderDecl);
  document.getElementById('declOrdCancel').addEventListener('click',function(){document.getElementById('declOrderModal').style.display='none';});
}
function doOrderDecl(){
  var d=declOrderState;
  document.querySelectorAll('.declord-pdate').forEach(function(inp){var i=+inp.dataset.i;if(d.products[i])d.products[i].prodDate=inp.value;});
  d.recipient=document.getElementById('declOrdRecipient').value.trim();
  d.date=document.getElementById('declOrdDate').value;
  d.lot=document.getElementById('declOrdLot').value.trim();
  d.number=document.getElementById('declOrdNum').value.trim()||d.number;
  var ctx={recipient:d.recipient,addr:d.addr,date:d.date,lot:d.lot,number:d.number,products:d.products};
  var stat=document.getElementById('declOrdStatus');var go=document.getElementById('declOrdGo');
  if(stat)stat.textContent='Готовлю PDF…';if(go)go.disabled=true;
  declRenderPdf(ctx,true,function(b64){
    if(!b64){if(stat)stat.textContent='Ошибка PDF';if(go)go.disabled=false;return;}
    var fname=declFileName(ctx);
    cloudOrderDocUpload(d.orderId,'deklaracija',ctx.number,fname,'application/pdf',b64).then(function(j){
      if(go)go.disabled=false;
      if(j&&j.ok&&j.doc){
        var oo=null;adminOrders.forEach(function(x){if(x.order_id===d.orderId)oo=x;});if(oo)oo.docs=(oo.docs||[]).concat([j.doc]);
        docConfig.counters.deklaracija=(docConfig.counters.deklaracija||0)+1;
        cloudPut('docConfig',docConfig);
        declEnsurePartner(ctx.recipient);
        declArchiveAdd(ctx,{url:j.doc.url,view:j.doc.view},'order',d.orderId);
        document.getElementById('declOrderModal').style.display='none';
        toast('Декларация прикреплена к заказу и в архив');renderAdminOrders();
      } else{if(stat)stat.textContent=(j&&j.error==='drive')?'Нет доступа к Drive':'Не удалось прикрепить';}
    }).catch(function(){if(go)go.disabled=false;if(stat)stat.textContent='Ошибка соединения';});
  });
}
(function(){var c=document.getElementById('declOrderClose');if(c)c.addEventListener('click',function(){document.getElementById('declOrderModal').style.display='none';});})();

/* ---------- инициализация таба ---------- */
function declCloudReload(cb){
  var st=document.getElementById('declCloudStat');
  if(!GAS_URL){if(st){st.textContent='⚠️ Облако не настроено — нажмите «Облако…» вверху и вставьте адрес веб-приложения + мастер-ключ';st.style.color='#c0392b';}if(cb)cb(false);return;}
  if(st){st.textContent='Облако: загружаю…';st.style.color='';}
  fetch(GAS_URL,{method:'POST',headers:{'Content-Type':'text/plain;charset=utf-8'},
    body:JSON.stringify({master:MASTER,pull:true})}).then(function(r){return r.json();}).then(function(j){
    if(j&&j.ok)cloudState='on';
    var dp=(j&&j.ok&&j.data&&j.data.declProducts&&typeof j.data.declProducts==='object')?j.data.declProducts:null;
    if(dp)declProducts=dp;
    if(j&&j.ok&&j.data&&Array.isArray(j.data.declArchive))declArchive=j.data.declArchive;
    var n=dp?Object.keys(dp).filter(function(k){var d=dp[k];return d&&(d.sastavRu||d.sastavSr||(d.alg&&d.alg.length)||(d.nutr&&Object.keys(d.nutr).length));}).length:0;
    if(st){
      if(!(j&&j.ok)){st.textContent='✗ Сервер ответил с ошибкой: '+((j&&j.error)||'нет ok')+' (проверьте мастер-ключ / развёртывание)';st.style.color='#c0392b';}
      else if(dp){st.textContent='✓ Облако на связи. В облаке заполнено продуктов: '+n;st.style.color='#1e7e34';}
      else{st.textContent='✗ Облако на связи, но ключа declProducts ещё НЕТ — сохраните справочник (если после сохранения не появляется: Code.gs не переразвёрнут)';st.style.color='#c0392b';}
    }
    if(cb)cb(true,n,!!dp);
  }).catch(function(){if(st){st.textContent='⚠️ Не удалось связаться с облаком (сеть/адрес). Проверьте «Облако…»';st.style.color='#c0392b';}if(cb)cb(false);});
}
function initDeclTab(){
  renderDeclPick();
  declCloudReload(function(){renderDeclRef();renderLabelBuilder();renderDeclArchive();});
  initLabelUi();
  var di=document.getElementById('declDate');if(di&&!di.value)di.valueAsDate=new Date();
  var lo=document.getElementById('declLot');if(lo&&!lo.value)lo.value=declLotFromDate(di?di.value:'');
  var nu=document.getElementById('declNum');if(nu&&!nu.value)nu.value=declNextNum();
  if(di&&!di._declb){di._declb=1;di.addEventListener('change',function(){var l=document.getElementById('declLot');if(l)l.value=declLotFromDate(di.value);});}
  var upd=document.getElementById('declUpdated');
  var sv=document.getElementById('declSave');
  if(sv&&!sv._b){sv._b=1;sv.addEventListener('click',function(){
    if(!GAS_URL){toast('Облако не настроено — нажмите «Облако…» вверху и вставьте адрес веб-приложения + мастер-ключ.');return;}
    sv.disabled=true;sv.textContent='Сохраняю…';
    var expectKeys=Object.keys(declProducts);
    fetch(GAS_URL,{method:'POST',headers:{'Content-Type':'text/plain;charset=utf-8'},
      body:JSON.stringify({master:MASTER,key:'declProducts',value:declProducts})})
    .then(function(r){return r.json();}).then(function(j){
      if(!(j&&j.ok))throw new Error((j&&j.error)||'ответ без ok');
      // ПРОВЕРКА: читаем обратно — реально ли записалось на сервере
      sv.textContent='Проверяю…';
      return fetch(GAS_URL,{method:'POST',headers:{'Content-Type':'text/plain;charset=utf-8'},
        body:JSON.stringify({master:MASTER,pull:true})}).then(function(r){return r.json();});
    }).then(function(pj){
      sv.disabled=false;sv.textContent='Сохранить справочник';
      var saved=(pj&&pj.ok&&pj.data&&pj.data.declProducts&&typeof pj.data.declProducts==='object')?pj.data.declProducts:null;
      var ok=saved&&expectKeys.every(function(k){return saved[k]!=null;});
      if(ok){setSync('on');if(upd)upd.textContent='Сохранено и проверено '+new Date().toLocaleTimeString('ru-RU');toast('✓ Справочник сохранён и проверен на сервере');renderDeclRef();}
      else{setSync('err');
        toast('⚠️ Сервер НЕ записал справочник. Нужно обновить Code.gs: в ALLOWED_KEYS добавить declProducts и сделать Развернуть → Новая версия.');}
    }).catch(function(e){sv.disabled=false;sv.textContent='Сохранить справочник';setSync('err','Не сохранилось');toast('НЕ сохранилось: '+(e&&e.message||'ошибка соединения'));});});}
  var rl=document.getElementById('declReload');
  if(rl&&!rl._b){rl._b=1;rl.addEventListener('click',function(){declCloudReload(function(){renderDeclRef();});});}
  var ar=document.getElementById('declArchReload');
  if(ar&&!ar._b){ar._b=1;ar.addEventListener('click',function(){
    if(!GAS_URL){toast('Облако не настроено');return;}
    fetch(GAS_URL,{method:'POST',headers:{'Content-Type':'text/plain;charset=utf-8'},body:JSON.stringify({master:MASTER,pull:true})})
      .then(function(r){return r.json();}).then(function(j){if(j&&j.ok&&j.data&&Array.isArray(j.data.declArchive))declArchive=j.data.declArchive;renderDeclArchive();}).catch(function(){toast('Ошибка обновления');});});}
  var pf=document.getElementById('declPdf');
  if(pf&&!pf._b){pf._b=1;pf.addEventListener('click',function(){
    var c=declManualCtx();if(!c.products.length){toast('Отметьте хотя бы один продукт');return;}
    toast('Готовлю PDF…');pf.disabled=true;
    declRenderPdf(c,true,function(b64){
      pf.disabled=false;
      if(!b64){toast('Не удалось сформировать PDF');return;}
      declDownloadB64(b64,declFileName(c));
      declEnsurePartner(c.recipient);
      declDriveUpload(declFileName(c),b64,function(drive){
        declArchiveAdd(c,drive,'manual','');
        declBumpCounter();
        var n=document.getElementById('declNum');if(n)n.value=declNextNum();
        renderDeclArchive();
        toast(drive?'Декларация скачана и сохранена в архив':'Декларация скачана (в архив без PDF — нет облака)');
      });
    });
  });}
}
(function(){var t=document.querySelector('.tab[data-tab="declar"]');if(t)t.addEventListener('click',initDeclTab);})();

initLock(bootApp);
